    {'code': 'US', 'name': 'USA', 'flag': '🇺🇸', 'ticker': '^GSPC'},
    {'code': 'Germany', 'name': 'Germany', 'flag': '🇩🇪', 'ticker': '^GDAXI'},
    {'code': 'France', 'name': 'France', 'flag': '🇫🇷', 'ticker': '^FCHI'},
    {'code': 'Japan', 'name': 'Japan', 'flag': '🇯🇵', 'ticker': '^N225'},
