    {'code': 'India', 'name': 'India', 'flag': '🇮🇳', 'ticker': '^NSEI'},
    {'code': 'Brazil', 'name': 'Brazil', 'flag': '🇧🇷', 'ticker': '^BVSP'},
    {'code': 'Russia', 'name': 'Russia', 'flag': '🇷🇺', 'ticker': 'IMOEX.ME'},
